mapper.select:
SELECT COUNT(*) FROM activities
WHERE start_time >= #{startTime}
  AND start_time <= #{endTime}

SELECT COUNT(DISTINCT ap.student_no)
FROM activity_participants ap
INNER JOIN activities a ON ap.activity_id = a.id
WHERE a.start_time >= #{startTime}
  AND a.start_time <= #{endTime}

SELECT COUNT(*) FROM users
WHERE created_at >= #{startTime}
  AND created_at <= #{endTime}

SELECT COUNT(*) FROM activities
WHERE status = 'ActivityEnded'
  AND end_time >= #{startTime}
  AND end_time <= #{endTime}

SELECT COUNT(*)
FROM users


        AND college = #{college}


        AND grade = #{grade}


        AND clazz = #{clazz}

SELECT COALESCE(SUM(total_hours), 0)
FROM users


        AND college = #{college}


        AND grade = #{grade}


        AND clazz = #{clazz}

SELECT COUNT(DISTINCT ap.id)
FROM activity_participants ap
INNER JOIN users u ON ap.student_no = u.student_no


        AND u.college = #{college}


        AND u.grade = #{grade}


        AND u.clazz = #{clazz}

SELECT u.student_no as studentNo, u.username as name, u.college as college, u.grade as grade, u.clazz as clazz, COALESCE(u.total_hours, 0) as totalDuration, COUNT(DISTINCT ap.activity_id) as activityCount FROM users u LEFT JOIN activity_participants ap ON u.student_no = ap.student_no
AND u.college = #{college}
AND u.grade = #{grade}
AND u.clazz = #{clazz}
GROUP BY u.student_no, u.username, u.college, u.grade, u.clazz, u.total_hours
ORDER BY totalDuration DESC ASC
ORDER BY activityCount DESC ASC
ORDER BY totalDuration DESC
LIMIT #{pageSize} OFFSET #{offset}
